package flags

import (
	"testing"
)

func TestParse(t *testing.T) {
	tests := []struct {
		name      string
		args      []string
		wantAgent string
		wantTeam  string
		wantErr   bool
	}{
		{
			name: "full flag set from PLAN.md example",
			args: []string{
				"--agent-id", "fix-auth@myteam",
				"--agent-name", "fix-auth",
				"--team-name", "myteam",
				"--agent-color", "blue",
				"--parent-session-id", "abc123",
				"--dangerously-skip-permissions",
				"--permission-mode", "acceptEdits",
				"--plan-mode-required",
				"--teammate-mode", "auto",
				"--agent-type", "custom",
				"--model", "claude-sonnet-4-6",
			},
			wantAgent: "fix-auth",
			wantTeam:  "myteam",
		},
		{
			name:      "equals form",
			args:      []string{"--agent-name=fix-auth", "--team-name=myteam"},
			wantAgent: "fix-auth",
			wantTeam:  "myteam",
		},
		{
			name:    "missing agent-name",
			args:    []string{"--team-name", "myteam"},
			wantErr: true,
		},
		{
			name:    "missing team-name",
			args:    []string{"--agent-name", "fix-auth"},
			wantErr: true,
		},
		{
			name:    "empty args",
			args:    []string{},
			wantErr: true,
		},
		{
			name: "flags in different order",
			args: []string{
				"--team-name", "myteam",
				"--model", "opus",
				"--agent-name", "builder",
			},
			wantAgent: "builder",
			wantTeam:  "myteam",
		},
		{
			name: "unknown flags preserved in AllArgs",
			args: []string{
				"--agent-name", "a",
				"--team-name", "t",
				"--future-flag", "val",
				"--another",
			},
			wantAgent: "a",
			wantTeam:  "t",
		},
		{
			name:    "agent-name at end without value",
			args:    []string{"--team-name", "t", "--agent-name"},
			wantErr: true,
		},
		{
			// BUG: --agent-name= with empty value falls through to the
			// "name != '' && i+1 < len(args)" branch, consuming the next
			// arg (--team-name) as the agent-name value. This leaves
			// team-name missing.
			name:    "equals with empty value grabs next arg (known bug)",
			args:    []string{"--agent-name=", "--team-name", "t"},
			wantErr: true,
		},
		{
			name:      "duplicate flags last wins",
			args:      []string{"--agent-name", "a", "--agent-name", "b", "--team-name", "t"},
			wantAgent: "b",
			wantTeam:  "t",
		},
		{
			name:    "path traversal in agent-name rejected",
			args:    []string{"--agent-name", "../../../admin", "--team-name", "t"},
			wantErr: true,
		},
		{
			name:    "nil args",
			args:    nil,
			wantErr: true,
		},
		{
			name:    "team-name at end without value",
			args:    []string{"--agent-name", "a", "--team-name"},
			wantErr: true,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			got, err := Parse(tt.args)
			if tt.wantErr {
				if err == nil {
					t.Fatal("expected error, got nil")
				}
				return
			}
			if err != nil {
				t.Fatalf("unexpected error: %v", err)
			}
			if got.AgentName != tt.wantAgent {
				t.Errorf("AgentName = %q, want %q", got.AgentName, tt.wantAgent)
			}
			if got.TeamName != tt.wantTeam {
				t.Errorf("TeamName = %q, want %q", got.TeamName, tt.wantTeam)
			}
			// AllArgs must always equal the original input
			if len(got.AllArgs) != len(tt.args) {
				t.Fatalf("AllArgs length = %d, want %d", len(got.AllArgs), len(tt.args))
			}
			for i, a := range got.AllArgs {
				if a != tt.args[i] {
					t.Errorf("AllArgs[%d] = %q, want %q", i, a, tt.args[i])
				}
			}
		})
	}
}

func TestValidateAgentName(t *testing.T) {
	tests := []struct {
		name    string
		input   string
		wantErr bool
	}{
		{"valid simple", "fix-auth", false},
		{"valid with hyphens", "my-agent-123", false},
		{"empty", "", true},
		{"path traversal", "../admin", true},
		{"double dot in middle", "foo..bar", true},
		{"forward slash", "team/agent", true},
		{"backslash", "team\\agent", true},
		{"starts with dot", ".hidden", true},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			err := ValidateAgentName(tt.input)
			if tt.wantErr && err == nil {
				t.Errorf("ValidateAgentName(%q) expected error, got nil", tt.input)
			}
			if !tt.wantErr && err != nil {
				t.Errorf("ValidateAgentName(%q) unexpected error: %v", tt.input, err)
			}
		})
	}
}

