  1→package cli
  2→
  3→import (
  4→	"fmt"
  5→	"os"
  6→	"os/exec"
  7→	"path/filepath"
  8→	"strings"
  9→
 10→	"github.com/spf13/cobra"
 11→
 12→	"github.com/agentsea/agentsea/internal/detect"
 13→	"github.com/agentsea/agentsea/internal/flags"
 14→	"github.com/agentsea/agentsea/internal/gitops"
 15→	"github.com/agentsea/agentsea/internal/sandbox"
 16→	"github.com/agentsea/agentsea/internal/workspace"
 17→)
 18→
 19→func teammateWrapperCmd() *cobra.Command {
 20→	return &cobra.Command{
 21→		Use:                "teammate-wrapper",
 22→		Short:              "Wrap a teammate spawn in a bwrap sandbox",
