import (
	"fmt"
	"os"
	"os/exec"
	"path/filepath"
	"strings"

	"github.com/spf13/cobra"

	"github.com/agentsea/agentsea/internal/detect"
	"github.com/agentsea/agentsea/internal/flags"
	"github.com/agentsea/agentsea/internal/gitops"
	"github.com/agentsea/agentsea/internal/sandbox"
	"github.com/agentsea/agentsea/internal/workspace"
)

func teammateWrapperCmd() *cobra.Command {
	return &cobra.Command{
		Use:                "teammate-wrapper",
		Short:              "Wrap a teammate spawn in a bwrap sandbox",
		Hidden:             true,
		DisableFlagParsing: true,
		RunE: func(cmd *cobra.Command, args []string) error {
			return runTeammateWrapper(args)
		},
	}
}

func runTeammateWrapper(args []string) error {
	// 1. Parse teammate flags
	parsed, err := flags.Parse(args)
	if err != nil {
		return fmt.Errorf("parsing flags: %w", err)
	}

	// 2. Find workspace config from cwd
	ws, err := workspace.Detect()
	if err != nil {
		return fmt.Errorf("detecting workspace: %w", err)
	}

	// 3. Provision agent workspace (idempotent — skip if already exists)
	agentRepo := ws.AgentRepoPath(parsed.AgentName)
	agentSSH := ws.AgentSSHPath(parsed.AgentName)

	if _, err := os.Stat(agentRepo); os.IsNotExist(err) {
		if err := gitops.CloneAgent(ws.CanonicalPath(), agentRepo, parsed.AgentName); err != nil {
			return fmt.Errorf("cloning agent repo: %w", err)
		}
		if err := gitops.WriteAgentContext(agentRepo); err != nil {
			return fmt.Errorf("writing agent context: %w", err)
		}
		if err := gitops.InstallPrePushHook(agentRepo); err != nil {
			return fmt.Errorf("installing pre-push hook: %w", err)
		}
		if err := gitops.GenerateDeployKey(agentSSH); err != nil {
			return fmt.Errorf("generating deploy key: %w", err)
		}
		if err := gitops.WriteSSHConfig(agentSSH, filepath.Join(agentSSH, "deploy_key")); err != nil {
			return fmt.Errorf("writing ssh config: %w", err)
		}
	}

	// 4. Find claude binary
	claudeBin, err := detect.FindClaudeBinary()
	if err != nil {
		return fmt.Errorf("finding claude binary: %w", err)
	}
	claudeDir := detect.ClaudeBinaryDir(claudeBin)

	// 5. Prepare writable .claude copy (dereference symlinks)
	claudeHome, err := prepareClaudeHome(ws, parsed.AgentName, parsed.TeamName)
	if err != nil {
		return fmt.Errorf("preparing claude home: %w", err)
	}

	// 6. Build bwrap config
	home := os.Getenv("HOME")
	cfg := sandbox.SandboxConfig{
		AgentRepo:    agentRepo,
		TeamMailbox:  ws.TeamMailboxPath(parsed.TeamName),
		ClaudeHome:   claudeHome,
		ClaudeBinDir: claudeDir,
		AgentSSHDir:  agentSSH,
		ExtraRO:      ws.Config.ExtraROMounts,
		ExtraRW:      ws.Config.ExtraRWMounts,
		Home:         home,
		User:         os.Getenv("USER"),
		WorkDir:      agentRepo,
	}

	// Only mount .claude.json if it exists
	claudeJSON := filepath.Join(home, ".claude.json")
	if _, err := os.Stat(claudeJSON); err == nil {
		cfg.ClaudeJSON = claudeJSON
	}

	if err := cfg.Validate(); err != nil {
		return fmt.Errorf("invalid sandbox config: %w", err)
	}

	// Ensure team mailbox directory exists
	if err := os.MkdirAll(ws.TeamMailboxPath(parsed.TeamName), 0755); err != nil {
		return fmt.Errorf("creating team mailbox dir: %w", err)
	}

	// 7. Inject agent profile flags (model, effort) if configured
	finalArgs := injectProfileFlags(parsed.AgentName, parsed.AllArgs, ws.Config.AgentProfiles)

	// 8. Inject --print "start" so Claude runs in non-interactive mode.
	// setsid (needed to prevent SIGTTOU from bwrap's process group)
	// detaches the controlling terminal, making stdout non-TTY.
	// Claude in non-interactive mode requires --print with a prompt.
	// The teammate's actual instructions come via the mailbox, not this prompt.
	finalArgs = append(finalArgs, "--print", "start")

	// 9. Build full command and exec
	bwrapArgs := cfg.Args()
	bwrapArgs = append(bwrapArgs, "--", claudeBin)
	bwrapArgs = append(bwrapArgs, finalArgs...)

	return sandbox.ExecSetsidBwrap(bwrapArgs)
}

// injectProfileFlags prepends --model and --effort flags from the agent profile
// if the lead hasn't already specified them explicitly. Agent-specific profiles
// take priority over the "default" profile.
func injectProfileFlags(agentName string, allArgs []string, profiles map[string]workspace.AgentProfile) []string {
	if len(profiles) == 0 {
		return allArgs
	}

	profile, ok := profiles[agentName]
	if !ok {
		profile, ok = profiles["default"]
		if !ok {
			return allArgs
		}
	}

	hasModel := hasFlag(allArgs, "--model")
	hasEffort := hasFlag(allArgs, "--effort")

	var inject []string
	if profile.Model != "" && !hasModel {
		inject = append(inject, "--model", profile.Model)
	}
	if profile.Effort != "" && !hasEffort {
		inject = append(inject, "--effort", profile.Effort)
	}

	if len(inject) == 0 {
		return allArgs
	}

	result := make([]string, 0, len(inject)+len(allArgs))
	result = append(result, inject...)
	result = append(result, allArgs...)
	return result
}

// hasFlag checks whether a flag (e.g. "--model") is already present in args,
// handling both "--flag value" and "--flag=value" forms.
func hasFlag(args []string, flag string) bool {
	for _, arg := range args {
		if arg == flag || strings.HasPrefix(arg, flag+"=") {
			return true
		}
	}
	return false
}

// prepareClaudeHome creates a writable copy of ~/.claude/ with symlinks dereferenced.
// Returns the path to the copy.
func prepareClaudeHome(ws *workspace.Workspace, agentName, teamName string) (string, error) {
	target := filepath.Join(ws.Dir, "agents", agentName, "claude-home")

	if _, err := os.Stat(target); os.IsNotExist(err) {
		src := filepath.Join(os.Getenv("HOME"), ".claude")

		// cp -aL dereferences symlinks (settings.json, CLAUDE.md may be symlinks to dotfiles)
		// Fall back to cp -a if -aL fails, then to mkdir as last resort.
		if out, err := exec.Command("cp", "-aL", src, target).CombinedOutput(); err != nil {
			if out2, err2 := exec.Command("cp", "-a", src, target).CombinedOutput(); err2 != nil {
				if err3 := os.MkdirAll(target, 0755); err3 != nil {
					return "", fmt.Errorf("cp -aL: %s, cp -a: %s, mkdir: %w", out, out2, err3)
				}
			}
		}
	}

	// Ensure teams/<teamName> subdir exists inside the copy for mailbox config
	teamsDir := filepath.Join(target, "teams", teamName)
	if err := os.MkdirAll(teamsDir, 0755); err != nil {
		return "", fmt.Errorf("creating teams dir in claude home: %w", err)
	}

	// Pre-create the project directory for the agent repo so Claude
	// recognizes it as a trusted workspace and skips the trust dialog.
	// Claude encodes paths by replacing "/" with "-" and stripping the leading "/".
	agentRepo := ws.AgentRepoPath(agentName)
	encodedPath := strings.ReplaceAll(agentRepo, "/", "-")
	projectDir := filepath.Join(target, "projects", encodedPath)
	if err := os.MkdirAll(projectDir, 0755); err != nil {
		return "", fmt.Errorf("creating project dir in claude home: %w", err)
	}

	return target, nil
}

package cli

import (
	"fmt"
	"os"
	"os/exec"
	"path/filepath"
	"strings"
	"syscall"

	"github.com/spf13/cobra"

	"github.com/agentsea/agentsea/internal/detect"
	"github.com/agentsea/agentsea/internal/settings"
)

func claudeCmd() *cobra.Command {
	return &cobra.Command{
		Use:   "claude [-- claude-args...]",
		Short: "Launch Claude Code with agent sandboxing enabled",
		Long: `Launches Claude Code with CLAUDE_CODE_TEAMMATE_COMMAND set to "sea teammate-wrapper".
All arguments after -- are passed through to claude.

Aborts if CLAUDE_CODE_TEAMMATE_COMMAND is already set in the environment.`,
		DisableFlagParsing: true,
		RunE: func(cmd *cobra.Command, args []string) error {
			return runClaude(args)
		},
	}
}

// claudeConfig holds resolved paths from preflight checks.
type claudeConfig struct {
	ClaudeBin string
	SeaBin    string
	Args      []string // args to pass to claude
}

// claudePreflight validates the environment and resolves paths.
// Separated from runClaude so it can be tested without syscall.Exec.
func claudePreflight(args []string) (*claudeConfig, error) {
	// Abort if CLAUDE_CODE_TEAMMATE_COMMAND is already set
	if val := os.Getenv("CLAUDE_CODE_TEAMMATE_COMMAND"); val != "" {
		return nil, fmt.Errorf("CLAUDE_CODE_TEAMMATE_COMMAND is already set to %q — cannot override", val)
	}

	// Find claude binary
	claudeBin, err := detect.FindClaudeBinary()
	if err != nil {
		return nil, fmt.Errorf("finding claude binary: %w", err)
	}

	// Resolve sea binary path for the env var
	seaBin, err := os.Executable()
	if err != nil {
		return nil, fmt.Errorf("resolving sea binary path: %w", err)
	}

	// Find bwrap to verify it exists before launching
	if _, err := exec.LookPath("bwrap"); err != nil {
		return nil, fmt.Errorf("bwrap not found on PATH — install with: sudo apt install bubblewrap")
	}

	// Strip leading "--" if present (cobra passes it through with DisableFlagParsing)
	claudeArgs := args
	if len(claudeArgs) > 0 && claudeArgs[0] == "--" {
		claudeArgs = claudeArgs[1:]
	}

	return &claudeConfig{
		ClaudeBin: claudeBin,
		SeaBin:    seaBin,
		Args:      claudeArgs,
	}, nil
}

func runClaude(args []string) error {
	cfg, err := claudePreflight(args)
	if err != nil {
		return err
	}

	// Build environment with CLAUDE_CODE_TEAMMATE_COMMAND injected.
	// Must be a single executable path — use sea-teammate-wrapper (installed alongside sea).
	wrapperBin := filepath.Join(filepath.Dir(cfg.SeaBin), "sea-teammate-wrapper")
	env := os.Environ()
	env = append(env, fmt.Sprintf("CLAUDE_CODE_TEAMMATE_COMMAND=%s", wrapperBin))

	// Ensure teammateMode=tmux in ~/.claude.json so CLAUDE_CODE_TEAMMATE_COMMAND
	// is actually used (v2.1.71+ defaults to in-process which bypasses it).
	if _, err := settings.EnsureGlobalConfig(); err != nil {
		fmt.Fprintf(os.Stderr, "Warning: could not update ~/.claude.json: %v\n", err)
	}

	// Inject --allowedTools for tmux commands so the lead agent doesn't
	// prompt for permission on every teammate management operation.
	// This is non-invasive: it doesn't modify the user's settings.json.
	allowedTools := strings.Join(settings.RequiredPermissions, " ")
	claudeArgs := append([]string{"--allowedTools", allowedTools}, cfg.Args...)

	// Build argv: claude [--allowedTools ...] [user args...]
	argv := append([]string{cfg.ClaudeBin}, claudeArgs...)

	fmt.Printf("Starting Claude Code with agent sandboxing enabled\n")
	fmt.Printf("  claude: %s\n", cfg.ClaudeBin)
	fmt.Printf("  wrapper: %s\n", wrapperBin)
	fmt.Println()

	// exec replaces the current process
	return syscall.Exec(cfg.ClaudeBin, argv, env)
}

